SELECT COUNT(1)
FROM t_sys_menu
WHERE parent_id = #{parentId}
  AND name = #{name}
  AND is_delete = 0

SELECT COUNT(1)
FROM t_sys_menu
WHERE parent_id = #{parentId}
  AND name = #{name}
  AND id != #{id}
  AND is_delete = 0

SELECT COUNT(1)
FROM t_sys_menu
WHERE path = #{path}
  AND id != #{id}
  AND is_delete = 0
